import org.apache.commons.math.distribution.NormalDistributionImpl;
import org.apache.commons.math.MathException;

public class TestNormalDistribution {
    public static void main(String[] args) {
        try {
            NormalDistributionImpl dist = new NormalDistributionImpl(0.0, 1.0);

            // Test case 1: Value more than 20 standard deviations above mean
            double result1 = dist.cumulativeProbability(21.0);
            System.out.println("Cumulative probability at 21.0: " + result1);
            if (Math.abs(result1 - 1.0) < 0.0001) {
                System.out.println("✓ Test 1 PASSED: Value above 20 std devs returns 1.0");
            } else {
                System.out.println("✗ Test 1 FAILED: Expected 1.0, got " + result1);
            }

            // Test case 2: Value more than 20 standard deviations below mean
            double result2 = dist.cumulativeProbability(-21.0);
            System.out.println("Cumulative probability at -21.0: " + result2);
            if (Math.abs(result2 - 0.0) < 0.0001) {
                System.out.println("✓ Test 2 PASSED: Value below 20 std devs returns 0.0");
            } else {
                System.out.println("✗ Test 2 FAILED: Expected 0.0, got " + result2);
            }

            // Test case 3: Normal value within 20 std devs should work normally
            double result3 = dist.cumulativeProbability(0.0);  // Should be 0.5 for standard normal
            System.out.println("Cumulative probability at 0.0: " + result3);
            if (Math.abs(result3 - 0.5) < 0.0001) {
                System.out.println("✓ Test 3 PASSED: Normal value works correctly");
            } else {
                System.out.println("✗ Test 3 FAILED: Expected ~0.5, got " + result3);
            }

            // Test case 4: Another normal value
            double result4 = dist.cumulativeProbability(1.0);  // Should be ~0.841 for standard normal
            System.out.println("Cumulative probability at 1.0: " + result4);
            if (Math.abs(result4 - 0.8413) < 0.01) {
                System.out.println("✓ Test 4 PASSED: Another normal value works correctly");
            } else {
                System.out.println("✗ Test 4 FAILED: Expected ~0.841, got " + result4);
            }

        } catch (MathException e) {
            System.out.println("MathException occurred: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

